// Note: imports use bare relative paths (no `.js` extension). Remotion's
// webpack-based bundler (used by `remotion render`) does NOT honour the
// TypeScript .js-extension convention; using `./MyVideo.js` here will fail
// the headless render with "MyVideo.js doesn't exist". Vite handles either
// form, so the dev server works regardless, but the CLI renderer is strict.
import { Composition, registerRoot } from 'remotion';
import { MyVideo } from './MyVideo';

/**
 * Remotion registers compositions via this Root component. Each <Composition />
 * declares a renderable video: its id (used by `remotion render`), the
 * component to render, dimensions, framerate, and total duration in frames.
 *
 * The default `MyVideo` is a 15-second 1080x1080 square composition at 30fps
 * (matches the geometry used in the canonical remotion-best-practices skill).
 * Common preset swaps:
 *   - 1080p landscape:  width={1920} height={1080}
 *   - Vertical / Reels: width={1080} height={1920}
 *
 * Add new compositions here as siblings.
 */
export const RemotionRoot = (): JSX.Element => (
  <>
    <Composition
      id="MyVideo"
      component={MyVideo}
      durationInFrames={450}
      fps={30}
      width={1080}
      height={1080}
      defaultProps={{ title: 'Hello from skillpack' }}
    />
  </>
);

// `registerRoot` is required when `remotion render` / `remotion studio` is
// pointed at this file as the entry point — without it the CLI errors with
// "this file does not contain registerRoot". Don't remove this call.
registerRoot(RemotionRoot);

import { AbsoluteFill, Sequence, useCurrentFrame, useVideoConfig, interpolate } from 'remotion';
import { Caption } from './Caption'; // no `.js` — Remotion's webpack bundler doesn't honour the TS .js convention

/**
 * Props are optional so the composition can be referenced from Root.tsx
 * without a zod schema. If you want type-safe defaultProps with validation,
 * add `@remotion/zod-types` and pass a `schema` to <Composition>.
 */
export interface MyVideoProps {
  title?: string;
}

/**
 * 15-second product-feature reel scaffold. The structure is:
 *   - Background fade-in (frames 0..30)
 *   - Title card with eased opacity (frames 10..150)
 *   - Three captions, one per ~3-second beat (sequenced via <Sequence />)
 *
 * Replace placeholders with your scenes. To add more scenes, append more
 * <Sequence /> children inside <AbsoluteFill /> below.
 */
export const MyVideo = ({ title = 'Hello from skillpack' }: MyVideoProps): JSX.Element => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const bgOpacity = interpolate(frame, [0, 30], [0, 1], { extrapolateRight: 'clamp' });
  const titleOpacity = interpolate(frame, [10, 40, 130, 150], [0, 1, 1, 0], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  return (
    <AbsoluteFill style={{ backgroundColor: '#0b0f17', color: '#fff', fontFamily: 'system-ui' }}>
      <AbsoluteFill
        style={{
          opacity: bgOpacity,
          background: 'radial-gradient(circle at 30% 20%, #2563eb33, transparent 60%)',
        }}
      />

      <AbsoluteFill
        style={{ justifyContent: 'center', alignItems: 'center', opacity: titleOpacity }}
      >
        <h1 style={{ fontSize: 96, margin: 0 }}>{title}</h1>
      </AbsoluteFill>

      <Sequence from={fps * 5} durationInFrames={fps * 3}>
        <Caption text="Built with skillpack" />
      </Sequence>
      <Sequence from={fps * 8} durationInFrames={fps * 3}>
        <Caption text="One command, ready to ship" />
      </Sequence>
      <Sequence from={fps * 11} durationInFrames={fps * 4}>
        <Caption text="Edit src/video/MyVideo.tsx" />
      </Sequence>
    </AbsoluteFill>
  );
};

